37	/// Pretty-print an `LNTerm` to a `String`.
38	///
39	/// Port of `prettyLNTerm` from `Term.LTerm` (`LTerm.hs`)
40	/// which delegates to `prettyTerm (text . show)`.
41	pub fn pretty_lnterm<T: PrettyTerm + ?Sized>(t: &T) -> String {
42	    let mut s = String::new();
43	    t.pretty_into(&mut s);
44	    s
45	}
46	
47	/// Trait for terms that know how to render themselves in the
48	/// Haskell-faithful pretty form.  Avoids a free-standing
49	/// generic-on-`Lit` function so [`Display`] can be implemented on
50	/// `Term<Lit<Name, LVar>>` directly.
51	pub trait PrettyTerm {
52	    fn pretty_into(&self, out: &mut String);
53	}
54	
55	// ---------------------------------------------------------------------
56	// Term<Lit<Name, LVar>> = LNTerm
57	// ---------------------------------------------------------------------
58	
59	impl PrettyTerm for Term<Lit<Name, LVar>> {
60	    fn pretty_into(&self, out: &mut String) {
61	        pp_term_lnterm(self, out);
62	    }
63	}
64	
65	fn pp_term_lnterm(t: &Term<Lit<Name, LVar>>, out: &mut String) {
66	    match t {
67	        Term::Lit(l) => pp_lit_lnterm(l, out),
68	        Term::App(FunSym::Ac(o), ts) => {
69	            // Haskell: `ppTerms (ppACOp o) 1 "(" ")" ts` — parenthesised
70	            // infix list joined by the AC operator symbol.
71	            out.push('(');
72	            for (i, child) in ts.iter().enumerate() {
73	                if i > 0 {
74	                    out.push_str(ac_op_symbol(*o));
75	                }
76	                pp_term_lnterm(child, out);
77	            }
78	            out.push(')');
79	        }
80	        // Haskell `prettyTerm` matches full `NoEqSym` equality (incl.
81	        // privacy/constructability), e.g. `s == expSym` — not just the
82	        // name+arity (Term.hs:274-277).
83	        Term::App(FunSym::NoEq(sym), ts) if ts.len() == 2 && *sym == exp_sym() => {
84	            pp_term_lnterm(&ts[0], out);
85	            out.push('^');
86	            pp_term_lnterm(&ts[1], out);
87	        }
88	        Term::App(FunSym::NoEq(sym), ts) if ts.len() == 2 && *sym == diff_sym() => {
89	            out.push_str("diff(");
90	            pp_term_lnterm(&ts[0], out);
91	            out.push_str(", ");
92	            pp_term_lnterm(&ts[1], out);
93	            out.push(')');
94	        }
95	        Term::App(FunSym::NoEq(sym), ts) if ts.is_empty() && *sym == nat_one_sym() => {
96	            out.push_str("%1");
97	        }
98	        Term::App(FunSym::NoEq(sym), _) if *sym == pair_sym() => {
99	            // Flatten right-associated pair trees.
100	            let mut flat: Vec<&Term<Lit<Name, LVar>>> = Vec::new();
101	            collect_pair_tail(t, &mut flat);
102	            out.push('<');
103	            for (i, c) in flat.iter().enumerate() {
104	                if i > 0 {
105	                    out.push_str(", ");
106	                }
107	                pp_term_lnterm(c, out);
108	            }
109	            out.push('>');
110	        }
111	        Term::App(FunSym::NoEq(sym), ts) => {
112	            out.push_str(&String::from_utf8_lossy(sym.name));
113	            if !ts.is_empty() {
114	                out.push('(');
115	                for (i, c) in ts.iter().enumerate() {
116	                    if i > 0 {
117	                        out.push_str(", ");
118	                    }
119	                    pp_term_lnterm(c, out);
120	                }
121	                out.push(')');
122	            }
123	        }
124	        Term::App(FunSym::C(CSym::EMap), ts) => {
125	            out.push_str(&String::from_utf8_lossy(EMAP_SYM_STRING));
126	            out.push('(');
127	            for (i, c) in ts.iter().enumerate() {
128	                if i > 0 {
129	                    out.push_str(", ");
130	                }
131	                pp_term_lnterm(c, out);
132	            }
133	            out.push(')');
134	        }
135	        Term::App(FunSym::List, ts) => {
136	            // `LIST(...)` — matches Haskell `ppFun "LIST" ts`
137	            out.push_str("LIST(");
138	            for (i, c) in ts.iter().enumerate() {
139	                if i > 0 {
140	                    out.push_str(", ");
141	                }
142	                pp_term_lnterm(c, out);
143	            }
144	            out.push(')');
145	        }
146	    }
147	}
148	
149	fn collect_pair_tail<'a>(
150	    t: &'a Term<Lit<Name, LVar>>,
151	    out: &mut Vec<&'a Term<Lit<Name, LVar>>>,
152	) {
153	    if let Term::App(FunSym::NoEq(sym), args) = t {
154	        if *sym == pair_sym() && args.len() == 2 {
155	            collect_pair_tail(&args[0], out);
156	            collect_pair_tail(&args[1], out);
157	            return;
158	        }
159	    }
160	    out.push(t);
161	}
162	
163	fn pp_lit_lnterm(l: &Lit<Name, LVar>, out: &mut String) {
164	    match l {
165	        Lit::Var(v) => pp_lvar(v, out),
166	        Lit::Con(n) => pp_name(n, out),
167	    }
168	}
169	
170	/// Mirror of Haskell `instance Show LVar` (LTerm.hs:525-532).
171	pub fn pp_lvar(v: &LVar, out: &mut String) {
172	    out.push_str(sort_prefix(v.sort));
173	    if v.name.is_empty() {
174	        out.push_str(&v.idx.to_string());
175	    } else if v.idx == 0 {
176	        out.push_str(v.name);
177	    } else {
178	        out.push_str(v.name);
179	        out.push('.');
180	        out.push_str(&v.idx.to_string());
181	    }
182	}
183	
184	/// Mirror of Haskell `instance Show Name` (LTerm.hs:231-235).
185	pub fn pp_name(n: &Name, out: &mut String) {
186	    let body = format!("'{}'", n.id.0);
187	    match n.tag {
188	        NameTag::Fresh => {
189	            out.push('~');
190	            out.push_str(&body);
191	        }
192	        NameTag::Pub => out.push_str(&body),
193	        NameTag::Node => {
194	            out.push('#');
195	            out.push_str(&body);
196	        }
197	        NameTag::Nat => {
198	            out.push('%');
199	            out.push_str(&body);
200	        }
201	    }
202	}
203	
204	pub fn ac_op_symbol(op: AcSym) -> &'static str {
205	    // Haskell `ppACOp` (Term.hs:283-286).
206	    //   Mult => "*"; Xor => "⊕"; Union => "++"; NatPlus => "%+"
207	    // We use the unicode char for Xor since the rest of the UI
208	    // already passes UTF-8 around and the JS frontend renders it.
209	    match op {
210	        AcSym::Mult => "*",
211	        AcSym::Xor => "\u{2295}",
212	        AcSym::Union => "++",
213	        AcSym::NatPlus => "%+",
214	    }
215	}
