591	fn render_signature(sig: &tamarin_term::maude_sig::MaudeSig) -> String {
592	    let mut out = String::new();
593	
594	    // builtins: ...  (only if any enabled)
595	    let mut builtins: Vec<&str> = Vec::new();
596	    if sig.enable_dh { builtins.push("diffie-hellman"); }
597	    if sig.enable_bp { builtins.push("bilinear-pairing"); }
598	    if sig.enable_mset { builtins.push("multiset"); }
599	    if sig.enable_nat { builtins.push("natural-numbers"); }
600	    if sig.enable_xor { builtins.push("xor"); }
601	    if !builtins.is_empty() {
602	        // HS renders builtins via the same `ppNonEmptyList'` as functions:
603	        // `(keyword_ "builtins:" <->) . fsep . punctuate comma`
604	        // (Term/Maude/Signature.hs:220-247,229-231) — so the list wraps through
605	        // the HughesPJ engine, not a flat join.
606	        out.push_str(&wrap_with_lead("builtins:", &builtins));
607	        out.push('\n');
608	    }
609	
610	    // functions: ...
611	    let funs = render_fun_syms(sig);
612	    if !funs.is_empty() {
613	        out.push_str(&wrap_with_lead("functions:", &funs));
614	        out.push('\n');
615	    }
616	
617	    // equations: ...
618	    let eqs = render_equations(sig);
619	    if !eqs.is_empty() {
620	        let key = if sig.eq_convergent { "equations [convergent]:" } else { "equations:" };
621	        // HS uses `sep [hdr, nest 2 (punctuate comma ds)]` for the
622	        // equations list — yields `hdr\n    eq1,\n    eq2,...` when
623	        // multiple equations.
624	        out.push_str(&sep_block_with_lead(key, &eqs));
625	        out.push('\n');
626	    }
627	
628	    out
629	}
