631	/// Render the function symbol list, sorted alphabetically by name (HS
632	/// uses `S.toList` over a Set ordered by the same key).
633	fn render_fun_syms(sig: &tamarin_term::maude_sig::MaudeSig) -> Vec<String> {
634	    use tamarin_term::function_symbols::{Constructability, Privacy};
635	    let mut items: Vec<(String, String)> = sig.st_fun_syms.iter().map(|sym| {
636	        let name = String::from_utf8_lossy(sym.name).to_string();
637	        let arity = sym.arity;
638	        let attr = match (sym.privacy, sym.constructability) {
639	            (Privacy::Public, Constructability::Constructor) => "",
640	            (Privacy::Public, Constructability::Destructor) => "[destructor]",
641	            (Privacy::Private, Constructability::Constructor) => "[private,constructor]",
642	            (Privacy::Private, Constructability::Destructor) => "[private,destructor]",
643	        };
644	        let rendered = format!("{}/{}{}", name, arity, attr);
645	        (name, rendered)
646	    }).collect();
647	    items.sort_by(|a, b| a.0.cmp(&b.0));
648	    items.into_iter().map(|(_, s)| s).collect()
649	}
