651	/// Render the equation list.  Each `CtxtStRule` has an LHS term and an
652	/// RHS term (after reading positions/term out of `StRhs`).  HS renders
653	/// `prettyCtxtStRule $ S.toList (stRules sig)` (Term/Maude/Signature.hs:220-247, see line 226),
654	/// i.e. equations in `S.toList` order.  `CtxtStRule` derives structural `Ord`,
655	/// so we emit them in the `st_rules` `BTreeSet` iteration order, which mirrors
656	/// HS's `S.toList` exactly.  We must NOT re-sort by the rendered pretty-string,
657	/// since that diverges from the structural (term-tree) order (e.g. AC products
658	/// pretty-print with a leading `(`, `exp` as infix `a^b`).
659	///
660	/// Each side is returned as a HughesPJ `Doc` (not a flat string) so that wide
661	/// function applications wrap at the ribbon width exactly as HS
662	/// `prettyCtxtStRule`/`prettyLNTerm` (SubtermRule.hs:122-123, Term.hs:295-296)
663	/// — the `ppFun f ts = text (f++"(") <> fsep (punctuate comma …) <> ")"` `fsep`
664	/// breaks at argument boundaries when the term overruns.  We reach the Doc path
665	/// by converting the `LNTerm` to a parser-AST `p::Term` (`lnterm_to_parser`,
666	/// the same conversion already used elsewhere) and rendering it through
667	/// `pf::term_doc` (= HS `prettyTerm`).
668	fn render_equations(sig: &tamarin_term::maude_sig::MaudeSig) -> Vec<(crate::pretty_hpj::Doc, crate::pretty_hpj::Doc)> {
669	    let mut items = Vec::new();
670	    for r in &sig.st_rules {
671	        let lhs = pf::term_doc(&lnterm_to_parser(&r.lhs));
672	        let rhs = pf::term_doc(&lnterm_to_parser(&r.rhs.term));
673	        items.push((lhs, rhs));
674	    }
675	    items
676	}
