678	/// Port of HS `checkEquationsSubtermConvergence` (Wellformedness.hs:1222-1232).
679	///
680	/// HS works on `thyEquations thy = S.toList (stRules sig)` — the SIGNATURE's
681	/// subterm-rule Set, NOT the parser-AST `equations:` blocks.  The parser-level
682	/// `tamarin_parser::wf::subterm_convergence_report` approximates this on the
683	/// parser AST but (a) keeps the source order rather than the `Ord CtxtStRule`
684	/// Set order, and (b) renders each equation on a single flat line (no
685	/// width-wrapping), because the `tamarin-parser` crate has no access to the
686	/// HughesPJ engine.  This function — living in `tamarin-theory`, which has the
687	/// elaborated `MaudeSig` plus the ported HughesPJ printer — reproduces HS
688	/// byte-for-byte:
689	///
690	///   * order = `sig.st_rules` `BTreeSet` iteration = HS `S.toList` (derived
691	///     `Ord CtxtStRule`), so e.g. `f1, f2, f3, g` rather than source order
692	///     `f1, g, f2, f3`;
693	///   * each equation = `prettyCtxtStRule r = sep [nest 2 lhs, "=" <-> rhs]`
694	///     (SubtermRule.hs:122-123), rendered via `pf::term_doc` so a wide RHS
695	///     wraps (HS `prettyTerm`'s `fsep` ppFun, Term.hs:295-296);
696	///   * suppressed entirely when `eqConvergent (sig thy)` is set
697	///     (`isUserMarkedConvergent`, Wellformedness.hs:1211-1214/1285).
698	///
699	/// `run.rs` calls this AFTER elaboration and REPLACES the parser-level entry
700	/// (same retain/re-add pattern used for "Message Derivation Checks").
701	pub fn subterm_convergence_report_wf(
702	    sig: &tamarin_term::maude_sig::MaudeSig,
703	) -> Vec<tamarin_parser::wf::WfError> {
704	    use tamarin_parser::wf::{underline_topic, WfError};
705	    // HS: `if not (isUserMarkedConvergent thy) then checkEqs else []`
706	    // (Wellformedness.hs:1270-1286, see line 1285); `isUserMarkedConvergent thy = eqConvergent (sig thy)`.
707	    if sig.eq_convergent {
708	        return Vec::new();
709	    }
710	    // HS: `nonSubtermEquations = filterNonSubtermCtxtRule (thyEquations thy)`
711	    // = filter (not . isSubtermConvergentCtxtRule) (S.toList (stRules sig)).
712	    let non_conv: Vec<&tamarin_term::subterm_rule::CtxtStRule> = sig
713	        .st_rules
714	        .iter()
715	        .filter(|r| !tamarin_term::subterm_rule::is_subterm_convergent(r))
716	        .collect();
717	    if non_conv.is_empty() {
718	        return Vec::new();
719	    }
720	
721	    // Equation list: `vcat (map prettyCtxtStRule nonSubtermEquations)`, each
722	    // `sep [nest 2 lhs, "=" <-> rhs]`, all rendered inside prettyWfErrorReport's
723	    // outer `nest 2`.  Build it as one HughesPJ Doc so the wrap decision +
724	    // indentation are HS-exact.
725	    //
726	    // WIDTH: the WF report Doc is rendered by HS `addComment c = ... TextItem
727	    // ("", render c)` (TheoryObject.hs:702-703, see line 703), where `render = P.render` uses the
728	    // HughesPJ DEFAULT style (`lineLength = 100`, `ribbonsPerLine = 1.5`,
729	    // `ribbon = round (100 / 1.5) = 67`) — NOT the theory body's
730	    // `renderDoc` width of 110/73 (Console.hs:227-239, see line 236,392).  The pre-rendered
731	    // string is then emitted verbatim inside the `/* ... */` comment.  So the
732	    // equation list wraps at the 100/67 budget, e.g. `f3`/`f6` (inline width 73
733	    // from column 4) wrap while `f2` (66) stays inline.  This is a SEPARATE
734	    // width from the `equations:` block, which is part of the theory body and
735	    // renders at 110/73.
736	    const WF_LINE_LENGTH: usize = 100;
737	    const WF_RIBBON: usize = 67; // round(100 / 1.5)
738	    let eq_lines = {
739	        use crate::pretty_hpj::{self as hpj, Doc};
740	        let docs: Vec<Doc> = non_conv
741	            .iter()
742	            .map(|r| {
743	                let lhs = pf::term_doc(&lnterm_to_parser(&r.lhs)).nest(2);
744	                let rhs = pf::term_doc(&lnterm_to_parser(&r.rhs.term));
745	                let eq_doc = Doc::text("=").beside_sp(rhs);
746	                hpj::sep(vec![lhs, eq_doc])
747	            })
748	            .collect();
749	        // Outer `nest 2` from prettyWfErrorReport `(nest 2 . vcat ...)`.
750	        let mut s = hpj::vcat(docs).nest(2).render_with(WF_LINE_LENGTH, WF_RIBBON);
751	        s.push('\n');
752	        s
753	    };
754	
755	    // Assemble the full message block (topic header + intro + equations +
756	    // footer) — byte-identical to the parser-level version, only `eq_lines`
757	    // differs (proper order + width-wrap).
758	    let mut msg = String::new();
759	    msg.push_str(&underline_topic("Subterm Convergence Warning"));
760	    // terminate the underline, then the blank line before the intro (HS `$-$`)
761	    msg.push_str("\n\n");
762	    msg.push_str("  User-defined equations must be convergent and have the finite variant property. The following equations are not subterm convergent. If you are sure that the set of equations is nevertheless convergent and has the finite variant property, you can ignore this warning and continue \n");
763	    msg.push('\n'); // blank line after intro (HS `$-$` before vcat)
764	    msg.push_str(&eq_lines);
765	    // HS: `$-$ text " \n For more information..."` — note the leading space.
766	    msg.push_str("   \n For more information, please refer to the manual : https://tamarin-prover.com/manual/master/book/010_modeling-issues.html ");
767	
768	    vec![WfError::new("Subterm Convergence Warning", msg)]
769	}
