//! Open-side adapter for the vendored `pretty_clean` clean-room renderer (R1).
//!
//! This is workspace-authored glue: it only translates live
//! `tamarin_parser::ast` / `tamarin_term` values into the clean crate's own AST
//! subset and forwards to `pretty_clean`. No rendering logic lives here — every
//! byte of output comes out of the clean crate.

use crate::pretty_clean::ast as c;
use tamarin_parser::ast as p;
use tamarin_term::maude_sig::MaudeSig;

// ── term: parser AST -> clean AST (1:1 structural, the surfaces are identical) ─

/// Structural conversion of a parser-AST term into the clean-AST term.
pub fn term(t: &p::Term) -> c::Term {
    match t {
        p::Term::Var(v) => c::Term::Var(varspec(v)),
        p::Term::PubLit(s) => c::Term::PubLit(s.clone()),
        p::Term::FreshLit(s) => c::Term::FreshLit(s.clone()),
        p::Term::NatLit(s) => c::Term::NatLit(s.clone()),
        p::Term::Number(n) => c::Term::Number(*n),
        p::Term::NumberOne => c::Term::NumberOne,
        p::Term::NatOne => c::Term::NatOne,
        p::Term::DhNeutral => c::Term::DhNeutral,
        p::Term::App(f, args) => c::Term::App(f.clone(), args.iter().map(term).collect()),
        p::Term::AlgApp(n, a, b) => {
            c::Term::AlgApp(n.clone(), Box::new(term(a)), Box::new(term(b)))
        }
        p::Term::Pair(elems) => c::Term::Pair(elems.iter().map(term).collect()),
        p::Term::Diff(a, b) => c::Term::Diff(Box::new(term(a)), Box::new(term(b))),
        p::Term::BinOp(op, a, b) => {
            c::Term::BinOp(binop(*op), Box::new(term(a)), Box::new(term(b)))
        }
        p::Term::PatMatch(inner) => c::Term::PatMatch(Box::new(term(inner))),
    }
}

fn varspec(v: &p::VarSpec) -> c::VarSpec {
    c::VarSpec {
        name: v.name.clone(),
        idx: v.idx,
        sort: sort(v.sort),
        typ: v.typ.clone(),
    }
}

fn sort(s: p::SortHint) -> c::SortHint {
    match s {
        p::SortHint::Msg => c::SortHint::Msg,
        p::SortHint::Pub => c::SortHint::Pub,
        p::SortHint::Fresh => c::SortHint::Fresh,
        p::SortHint::Node => c::SortHint::Node,
        p::SortHint::Nat => c::SortHint::Nat,
        p::SortHint::Suffix(x) => c::SortHint::Suffix(suffix(x)),
        p::SortHint::Untagged => c::SortHint::Untagged,
    }
}

fn suffix(s: p::SuffixSort) -> c::SuffixSort {
    match s {
        p::SuffixSort::Msg => c::SuffixSort::Msg,
        p::SuffixSort::Pub => c::SuffixSort::Pub,
        p::SuffixSort::Fresh => c::SuffixSort::Fresh,
        p::SuffixSort::Node => c::SuffixSort::Node,
        p::SuffixSort::Nat => c::SuffixSort::Nat,
    }
}

fn binop(op: p::BinOp) -> c::BinOp {
    match op {
        p::BinOp::Exp => c::BinOp::Exp,
        p::BinOp::Mult => c::BinOp::Mult,
        p::BinOp::Union => c::BinOp::Union,
        p::BinOp::Xor => c::BinOp::Xor,
        p::BinOp::NatPlus => c::BinOp::NatPlus,
    }
}

// ── signature block: closed MaudeSig -> clean Signature ───────────────────────

/// Build the clean-AST `Signature` from the CLOSED `MaudeSig`.
///
/// The clean crate performs its own observable closure (it always re-adds the
/// base pairing symbols/equations and then dedups + sorts). We therefore hand
/// it the enabled line-builtins (for the `builtins:` line only — those five add
/// no function/equation entries in the clean expander) plus the fully-closed
/// `st_fun_syms` / `st_rules` as "user" declarations; the clean crate's dedup
/// merges the duplicated base pairing entries, so the merged set equals the
/// ported `render_fun_syms` / `render_equations` input.
pub fn signature(sig: &MaudeSig) -> c::Signature {
    use tamarin_term::function_symbols::{Constructability, Privacy};

    let mut builtins: Vec<String> = Vec::new();
    if sig.enable_dh {
        builtins.push("diffie-hellman".into());
    }
    if sig.enable_bp {
        builtins.push("bilinear-pairing".into());
    }
    if sig.enable_mset {
        builtins.push("multiset".into());
    }
    if sig.enable_nat {
        builtins.push("natural-numbers".into());
    }
    if sig.enable_xor {
        builtins.push("xor".into());
    }

    let functions: Vec<c::FunctionDecl> = sig
        .st_fun_syms
        .iter()
        .map(|s| c::FunctionDecl {
            name: String::from_utf8_lossy(s.name).into_owned(),
            arity: s.arity,
            private: matches!(s.privacy, Privacy::Private),
            destructor: matches!(s.constructability, Constructability::Destructor),
        })
        .collect();

    let equations: Vec<c::Equation> = sig
        .st_rules
        .iter()
        .map(|r| c::Equation {
            lhs: term(&crate::pretty_theory::lnterm_to_parser(&r.lhs)),
            rhs: term(&crate::pretty_theory::lnterm_to_parser(&r.rhs.term)),
        })
        .collect();

    c::Signature {
        builtins,
        functions,
        equations,
        convergent: sig.eq_convergent,
    }
}

/// The full signature section (header comment + blank line + `builtins:` /
/// `functions:` / `equations:` lines) with the trailing newline the theory
/// echo expects, rendered entirely by the clean crate. Drop-in for the ported
/// `render_signature` call site including the `// Function signature …` header
/// (the clean `render_signature_block` emits that header itself).
pub fn signature_section(sig: &MaudeSig) -> String {
    let mut s = crate::pretty_clean::render_signature_block(&signature(sig));
    s.push('\n');
    s
}

